class Solution:
    def pathInZigZagTree(self, label):
        def label_to_index(lbl):
            level = lbl.bit_length() - 1
            lo = 1 << level
            hi = (1 << (level + 1)) - 1
            if level % 2 == 0:
                idx = lbl - lo
            else:
                idx = hi - lbl
            return level, idx
        def index_to_label(level, idx):
            lo = 1 << level
            hi = (1 << (level + 1)) - 1
            if level % 2 == 0:
                return lo + idx
            return hi - idx
        path = []
        level, idx = label_to_index(label)
        while level >= 0:
            path.append(index_to_label(level, idx))
            idx //= 2
            level -= 1
        path.reverse()
        return path

