var pathInZigZagTree = function(label) {
    let level = 31 - Math.clz32(label);
    const path = [];
    let cur = label;
    while (cur >= 1) {
        path.push(cur);
        const lo = 1 << level;
        const hi = (1 << (level + 1)) - 1;
        const mirrored = lo + hi - cur;
        cur = Math.floor(mirrored / 2);
        level -= 1;
    }
    path.reverse();
    return path;
};
